"use strict";(globalThis.webpackChunklearnvertexnova=globalThis.webpackChunklearnvertexnova||[]).push([[8749],{1895(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome-vertexnova","metadata":{"permalink":"/blog/welcome-vertexnova","source":"@site/blog/2024-01-10-welcome-vertexnova.md","title":"Welcome to VertexNova Engine","description":"Welcome to VertexNova Engine - a modern, multi-platform rendering and visualization engine designed for clarity, portability, and steady evolution.","date":"2024-01-10T00:00:00.000Z","tags":[{"inline":false,"label":"Announcement","permalink":"/blog/tags/blog/tags/announcement","description":"Project announcements and updates"},{"inline":false,"label":"VertexNova","permalink":"/blog/tags/blog/tags/vertexnova","description":"Posts about VertexNova Engine"},{"inline":false,"label":"Engine","permalink":"/blog/tags/blog/tags/engine","description":"Graphics engine development"}],"readingTime":1.18,"hasTruncateMarker":true,"authors":[{"name":"Ajeet Singh Yadav","title":"VertexNova Engine Creator","url":"https://github.com/ajeetsinghyadav","page":{"permalink":"/blog/authors/ayadav"},"socials":{"github":"https://github.com/ajeetsinghyadav"},"imageURL":"https://github.com/ajeetsinghyadav.png","key":"ayadav"}],"frontMatter":{"slug":"welcome-vertexnova","title":"Welcome to VertexNova Engine","authors":["ayadav"],"tags":["announcement","vertexnova","engine"]},"unlisted":false},"content":"Welcome to **VertexNova Engine** - a modern, multi-platform rendering and visualization engine designed for clarity, portability, and steady evolution.\\n\\n\x3c!-- truncate --\x3e\\n\\n## What is VertexNova?\\n\\nVertexNova Engine (VNE) is a personal learning project focused on building a clean, maintainable multi-backend rendering engine. The project provides:\\n\\n- **Multi-backend rendering** - Unified API across OpenGL Desktop, OpenGL ES/WebGL, Metal, and Vulkan (WIP)\\n- **Cross-platform support** - macOS, iOS, Windows, Linux, and Web (Emscripten)\\n- **Modern C++ design** - Clean architecture with strict ownership and predictable lifetimes\\n- **Thin abstractions** - Clear layering with explicit control\\n\\n## Why VertexNova?\\n\\nThis project started as a learning journey in computer graphics and engine architecture. After working on 3D visualization projects professionally, I wanted to build my own engine from the ground up, learning from excellent references like:\\n\\n- [The Cherno\'s Game Engine Series](https://www.youtube.com/playlist?list=PLlrATfBNZ98dC-V-N3m0Go4deliWHPFwT)\\n- [LearnOpenGL](https://learnopengl.com/)\\n- [libigl (facebook/igl)](https://github.com/facebook/igl)\\n- [LLGL](https://github.com/LukasBanana/LLGL)\\n\\n## Current Status\\n\\n- Simple demos run on macOS, iOS, OpenGL desktop, and Web (Emscripten/WebGL)\\n- Vulkan backend is in progress\\n- More demos and tests are being added to cover concepts thoroughly\\n\\n## What\'s Next?\\n\\nCheck out the [Getting Started guide](/docs/intro) to begin learning with VertexNova, or explore the [Demos](/docs/docs/demos) to see what\'s currently working.\\n\\nVertexNova is under active development. Several libraries are open source on [GitHub](https://github.com/vertexnova); others remain private for now. Contributions, feedback, and questions are welcome!"}]}}')}}]);